def solve(age, is_male, waist_circumference_cm, bmi, systolic_bp_mmhg, has_family_history):
    # Step 1: calculate_age_score
    # Calculate the score based on the patient's age according to predefined age ranges.
    if 20 <= age <= 24:
        age_score = 0
    elif 25 <= age <= 34:
        age_score = 4
    elif 35 <= age <= 44:
        age_score = 8
    elif 45 <= age <= 54:
        age_score = 11
    elif 55 <= age <= 64:
        age_score = 12
    elif 65 <= age <= 74:
        age_score = 13
    else:
        age_score = 0  # default for out-of-range ages, though not specified
    yield {
        "step_name": "calculate_age_score",
        "step_description": "Calculate the score based on the patient's age according to predefined age ranges",
        "step_result": age_score,
        "unit": None
    }

    # Step 2: calculate_gender_score
    # Calculate the score based on the patient's gender.
    gender_score = 3 if is_male else 0
    yield {
        "step_name": "calculate_gender_score",
        "step_description": "Calculate the score based on the patient's gender",
        "step_result": gender_score,
        "unit": None
    }

    # Step 3: calculate_waist_score
    # Calculate the score based on waist circumference in centimeters.
    wc = waist_circumference_cm
    if wc <= 64.9:
        waist_score = 0
    elif 65.0 <= wc <= 69.9:
        waist_score = 3
    elif 70.0 <= wc <= 74.9:
        waist_score = 5
    elif 75.0 <= wc <= 79.9:
        waist_score = 7
    elif 80.0 <= wc <= 84.9:
        waist_score = 8
    elif 85.0 <= wc <= 89.9:
        waist_score = 10
    elif wc >= 90.0:
        waist_score = 11
    else:
        waist_score = 0  # default for values below 65.0 but not caught by <=64.9 (should be covered)
    yield {
        "step_name": "calculate_waist_score",
        "step_description": "Calculate the score based on waist circumference in centimeters",
        "step_result": waist_score,
        "unit": None
    }

    # Step 4: calculate_bmi_score
    # Calculate the score based on Body Mass Index (BMI).
    if bmi < 23.0:
        bmi_score = 0
    elif 23.0 <= bmi <= 24.9:
        bmi_score = 3
    elif 25.0 <= bmi <= 29.9:
        bmi_score = 5
    elif bmi >= 30.0:
        bmi_score = 6
    else:
        bmi_score = 0  # default fallback
    yield {
        "step_name": "calculate_bmi_score",
        "step_description": "Calculate the score based on Body Mass Index (BMI)",
        "step_result": bmi_score,
        "unit": None
    }

    # Step 5: calculate_sbp_score
    # Calculate the score based on systolic blood pressure in mmHg.
    sbp = systolic_bp_mmhg
    if sbp < 110:
        sbp_score = 0
    elif 110 <= sbp <= 119:
        sbp_score = 1
    elif 120 <= sbp <= 129:
        sbp_score = 2
    elif 130 <= sbp <= 139:
        sbp_score = 3
    elif 140 <= sbp <= 149:
        sbp_score = 5
    elif 150 <= sbp <= 159:
        sbp_score = 6
    elif 160 <= sbp <= 169:
        sbp_score = 6
    elif sbp >= 170:
        sbp_score = 7
    else:
        sbp_score = 0  # default fallback
    yield {
        "step_name": "calculate_sbp_score",
        "step_description": "Calculate the score based on systolic blood pressure in mmHg",
        "step_result": sbp_score,
        "unit": None
    }

    # Step 6: calculate_family_history_score
    # Calculate the score based on family history of diabetes in first-degree relatives.
    family_history_score = 7 if has_family_history else 0
    yield {
        "step_name": "calculate_family_history_score",
        "step_description": "Calculate the score based on family history of diabetes in first-degree relatives",
        "step_result": family_history_score,
        "unit": None
    }

    # Final output: total risk score
    total_risk_score = age_score + gender_score + waist_score + bmi_score + sbp_score + family_history_score
    return total_risk_score
